function solve(nums) {
    const N = nums.length;

    // Step 1: Find the peak index P
    // P is the last index where the sequence is strictly increasing relative to its left neighbor.
    let peakIndex = 0;
    for (let i = 1; i < N; i++) {
        if (nums[i] > nums[i - 1]) {
            peakIndex = i;
        } else {
            // The sequence starts decreasing or plateaus (though plateauing is disallowed by the problem description)
            break; 
        }
    }

    const P = peakIndex;

    // Step 2: Calculate Sum_Inc (0 to P inclusive)
    let sumInc = 0;
    for (let i = 0; i <= P; i++) {
        sumInc += nums[i];
    }

    // Step 3: Calculate Sum_Dec (P to N-1 inclusive)
    let sumDec = 0;
    for (let i = P; i < N; i++) {
        sumDec += nums[i];
    }

    // Step 4: Comparison
    if (sumInc > sumDec) {
        return 0;
    } else if (sumDec > sumInc) {
        return 1;
    } else {
        return -1;
    }
}
